window.DOC_GUIDES = {
  overview: {
    title: "QuantVolt documentation", eyebrow: `QuantVolt v${window.API_DATA.version}`,
    description: "Quantitative analysis for European power, gas and carbon markets.",
    body: `
      <div class="hero-doc"><div><p>QuantVolt is a pure-computation Python library for reproducible pricing, risk, hedging, forward-curve and physical-asset experiments. You provide immutable market assumptions; QuantVolt returns typed results.</p><div class="button-row"><a class="primary-button" href="#/guide/quickstart">Get started</a><a class="secondary-button" href="#/api">Browse the API</a></div></div><div class="install-card"><span>Install with pip</span><code>pip install quantvolt</code><button data-copy="pip install quantvolt">Copy</button><small>Requires Python 3.11+</small></div></div>
      <h2 id="what-you-can-do">What you can do</h2>
      <div class="topic-grid">
        <a href="#/guide/curves"><b>Forward curves</b><span>Build interpolated, arbitrage-checked commodity curves.</span><i>→</i></a>
        <a href="#/guide/pricing"><b>Price derivatives</b><span>Options, futures, swaps, spreads, tolling and exotics.</span><i>→</i></a>
        <a href="#/guide/portfolio-risk"><b>Measure portfolio risk</b><span>VaR, CFaR, CVaR, stress and credit exposure.</span><i>→</i></a>
        <a href="#/guide/ppa"><b>Settle PPAs</b><span>Interval settlement, imbalance and realized hedges.</span><i>→</i></a>
        <a href="#/guide/assets"><b>Value physical assets</b><span>Thermal dispatch, storage and long-dated governance.</span><i>→</i></a>
        <a href="#/guide/statistics"><b>Research time series</b><span>Stationarity, normality, correlation and mean reversion.</span><i>→</i></a>
      </div>
      <h2 id="design">A small, explicit computational core</h2><div class="callouts"><div><b>Immutable</b><p>Frozen value objects and non-mutating computations.</p></div><div><b>Deterministic</b><p>Random algorithms accept a seed; equal inputs produce equal outputs.</p></div><div><b>Auditable</b><p>Validation fails before calculation and results serialize to plain dictionaries.</p></div></div>
      <h2 id="markets">Built for European energy</h2><p>Built-in configurations cover EEX Phelix DE/AT, EPEX SPOT zones, TTF, NBP and EUA. Caller-defined commodities extend the registry without changing library source.</p>
    `
  },
  why: {title:"Design scope", description:"The problem the shared value-object model solves, and the explicit boundaries around portfolio pricers, realized settlement and model coverage.", body:`
    <h2 id="the-problem">The integration problem</h2><p>A typical European energy desk assembles curve building, options pricing, storage/dispatch optimization and VaR reporting from separate tools, each with its own delivery-period definition, position-sign convention, volatility annualization, and definition of "spot" vs "day-ahead" vs "settlement" price. Moving a position between tools means hand-reconciling units, conventions and identifiers &mdash; a source of errors such as a heat rate applied on the wrong side of a spread, or an interpolation policy silently changed between two reports of the same curve.</p>
    <h2 id="shared-model">One shared computational model</h2><p>Curve construction, pricing, portfolio valuation, risk, realized settlement and physical-asset valuation consume and produce the same immutable value objects &mdash; the same <code>ForwardCurve</code>, <code>DeliveryPeriod</code>, <code>MarketData</code> and <code>Greeks</code> types flow from curve build through option pricing, portfolio valuation, the risk engine, and into realized PPA/hedge settlement. Three properties are enforced structurally:</p>
    <div class="callouts"><div><b>Deterministic</b><p>Every stochastic entry point takes an explicit seed; identical inputs and seed reproduce identical results.</p></div><div><b>Eagerly validated</b><p>Invalid inputs raise a typed <code>EnergyQuantError</code> before any computation runs.</p></div><div><b>Auditable</b><p>Every domain value object is a frozen dataclass that serializes to a plain dict, so a result can be logged, diffed and replayed.</p></div></div>
    <h2 id="registry">Pricer registry, separate from realized settlement</h2><p>Portfolio valuation is a caller-configurable dispatch: <code>DEFAULT_PRICERS</code> maps each native instrument type (futures, forwards, swaps, vanilla and spread options, tolling agreements, transmission/pipeline rights) to a pricer function; a caller registers additional pricers for its own instrument types without editing library source.</p><p><code>settle_ppa_frame</code> and <code>settle_energy_portfolio</code> compute what a producer actually earned from metered generation and observed prices &mdash; deterministic accounting, not a priced model &mdash; and that realized cash flow is never mislabeled as an NPV.</p>
    <h2 id="what-not">What QuantVolt is not</h2><ul>
      <li>A <code>PpaContract</code> or realized power-hedge position lands in a portfolio's <code>unpriced</code> list unless the caller registers a forward-looking pricer for it (via <code>make_ppa_pricer</code> or a caller-supplied function) &mdash; it is not in <code>DEFAULT_PRICERS</code>, because a PPA needs a caller-supplied generation/price model.</li>
      <li>Storage and thermal-dispatch valuation (<code>storage_intrinsic</code>, <code>storage_value</code>, <code>dispatch_deterministic</code>, <code>dispatch_value</code>) are asset-level engines: their results must be brought into a portfolio explicitly (for example as the replicating futures built from an intrinsic schedule).</li>
      <li>No market data ships with the package. The optional <code>quantvolt[data]</code> adapters fetch external observations and perform the only I/O in the library; the analytics core never depends on them and every function also accepts caller-owned data.</li>
      <li>Approximations are labelled: Kirk's spread-option formula is an approximation (Margrabe is the exact zero-strike case), Turnbull-Wakeman is a moment-matched approximation for the discrete arithmetic Asian average, and <code>bang_bang</code> dispatch is an approximate policy with its own hedge-reliability warning.</li>
      <li>Black-76 requires strictly positive forwards and strikes (its lognormal-forward assumption); it raises a <code>ValidationError</code> at a zero or negative forward. QuantVolt provides a separate Bachelier (normal-model) pricer, <code>price_bachelier_option</code>, for regimes where forwards or strikes may be zero or negative (power, and &mdash; since 2020 &mdash; oil). The library does not switch between these models automatically: the caller chooses the pricer, and the normal and lognormal volatility inputs are not interchangeable.</li>
    </ul>
    <h2 id="evidence">Evidence, not assertion</h2><p>These are checkable claims. The <a href="#/guide/validation">external validation page</a> compares QuantVolt's closed-form and Monte Carlo pricers against an independent reference implementation (QuantLib 1.43) and states which parts have not been externally cross-checked (the storage kernels, pending a .NET-capable environment for cmdty-storage). The three <a href="#/guide/end-to-end">worked tutorials</a> show the shared-model claim executed end to end, with every printed number captured from an actual run.</p>
  `},
  installation: {title:"Installation", description:"Install QuantVolt and its optional data layer.", body:`
    <h2 id="requirements">Requirements</h2><p>QuantVolt requires Python 3.11 or newer. The core depends on NumPy, SciPy, Polars and statsmodels; Monte Carlo path simulation uses the included native Rust extension.</p>
    <h2 id="pip">pip</h2>${codeBlock(`pip install quantvolt`, `Successfully installed quantvolt-${window.API_DATA.version}`, "shell")}
    <h2 id="uv">uv</h2>${codeBlock(`uv add quantvolt`, `Resolved and installed quantvolt`, "shell")}
    <h2 id="data-extra">Optional data adapters</h2>${codeBlock(`pip install "quantvolt[data]"`, `Adds httpx-powered provider adapters`, "shell")}
    <div class="admonition note"><b>Core/data separation</b><p>The analytics core performs no I/O. The optional adapters fetch external observations, but every calculation also accepts caller-owned data.</p></div>
    <h2 id="verify">Verify the installation</h2>${codeBlock(`import quantvolt as qv\nprint(qv.__version__)`, window.API_DATA.version)}
  `},
  quickstart: {title:"Quickstart", description:"Build a curve, price an option and measure portfolio risk.", body:`
    <p>This end-to-end example uses one market date and a small set of observed TTF contracts. Every block below is complete and runnable on its own. Full runnable script: <code>site/examples/verify_quickstart.py</code>.</p>
    <h2 id="curve">1. Build a forward curve</h2>${codeBlock(`from datetime import date\nimport quantvolt as qv\n\nmarket_date = date(2026, 7, 15)\nttf = qv.BUILT_IN_COMMODITIES["TTF"]\nobserved = [\n    qv.InstrumentPriceRecord("TTF-OCT26", ttf, qv.DeliveryPeriod(2026, 10), 31.40),\n    qv.InstrumentPriceRecord("TTF-DEC26", ttf, qv.DeliveryPeriod(2026, 12), 36.85),\n    qv.InstrumentPriceRecord("TTF-MAR27", ttf, qv.DeliveryPeriod(2027, 3), 34.10),\n]\ncurve = qv.CurveBuilder().build(\n    ttf, market_date, observed, interpolation="piecewise_linear"\n).curve\nfor node in curve.nodes:\n    print(node.period.year, node.period.month, node.price, node.status)`, `2026 10   31.40  observed\n2026 11   34.12  interpolated\n2026 12   36.85  observed\n2027 01   35.93  interpolated\n2027 02   35.02  interpolated\n2027 03   34.10  observed`, "python", miniCurve())}
    <h2 id="option">2. Price a European option</h2><p>This block re-declares the curve so it runs on its own; in one continuous program you would reuse the <code>curve</code> from step 1 instead.</p>${codeBlock(`from datetime import date\nimport quantvolt as qv\n\nmarket_date = date(2026, 7, 15)\nttf = qv.BUILT_IN_COMMODITIES["TTF"]\nobserved = [\n    qv.InstrumentPriceRecord("TTF-OCT26", ttf, qv.DeliveryPeriod(2026, 10), 31.40),\n    qv.InstrumentPriceRecord("TTF-DEC26", ttf, qv.DeliveryPeriod(2026, 12), 36.85),\n    qv.InstrumentPriceRecord("TTF-MAR27", ttf, qv.DeliveryPeriod(2027, 3), 34.10),\n]\ncurve = qv.CurveBuilder().build(\n    ttf, market_date, observed, interpolation="piecewise_linear"\n).curve\n\noption = qv.price_vanilla_option(qv.VanillaOptionRequest(\n    option_type="call", strike=38.0, notional=10_000.0,\n    forward=curve.price_at(qv.DeliveryPeriod(2026, 12)),\n    sigma=0.55, time_to_expiry=0.4, discount_factor=0.99,\n))\nprint(f"premium   EUR {option.premium:,.0f}")\nprint(f"delta     {option.greeks.delta:,.0f} EUR per EUR/MWh")`, `premium   EUR 45,663\ndelta     5,288 EUR per EUR/MWh`)}
    <h2 id="risk">3. Value and measure risk on a small position</h2><p>Build the <code>MarketData</code> the option step skipped, value a one-position portfolio, then run <code>RiskEngine.compute_risk</code>. Its <code>scenario_matrix</code> needs exactly one column per <code>(commodity, delivery period)</code> cell in the book's aggregated delta grid; this book touches one commodity (TTF) and one period (Dec-26), so the matrix is <code>(n_scenarios, 1)</code> &mdash; a book spanning more commodities or periods needs a wider matrix, or <code>compute_risk</code> raises a <code>ValidationError</code> naming both dimensions.</p>${codeBlock(`from datetime import date\nimport numpy as np\nimport quantvolt as qv\n\nmarket_date = date(2026, 7, 15)\nttf = qv.BUILT_IN_COMMODITIES["TTF"]\nobserved = [\n    qv.InstrumentPriceRecord("TTF-OCT26", ttf, qv.DeliveryPeriod(2026, 10), 31.40),\n    qv.InstrumentPriceRecord("TTF-DEC26", ttf, qv.DeliveryPeriod(2026, 12), 36.85),\n    qv.InstrumentPriceRecord("TTF-MAR27", ttf, qv.DeliveryPeriod(2027, 3), 34.10),\n]\ncurve = qv.CurveBuilder().build(\n    ttf, market_date, observed, interpolation="piecewise_linear"\n).curve\n\nfuture = qv.FuturesContract(\n    ttf, qv.DeliveryPeriod(2026, 12), contract_price=35.0, notional=5_000.0,\n)\nportfolio = qv.Portfolio(positions=(qv.Position(instrument=future),))\ndiscount_curve = qv.DiscountCurve(\n    reference_date=market_date,\n    tenors=(date(2026, 7, 16), date(2027, 12, 31)),\n    factors=(1.0, 0.96),\n)\nmarket = qv.MarketData(\n    forward_curves={"TTF": curve},\n    discount_curve=discount_curve,\n    valuation_date=market_date,\n)\nvaluation = qv.value_portfolio(portfolio, market)\n\nscenarios = np.random.default_rng(42).normal(loc=0.0, scale=1.5, size=(500, 1))\nrisk = qv.RiskEngine().compute_risk(list(valuation.priced), scenarios)\nprint(f"Book NPV    EUR {valuation.total_npv:,.0f}")\nprint(f"VaR 95      EUR {risk.var_95:,.0f}")\nprint(f"VaR 99      EUR {risk.var_99:,.0f}")\nprint(f"CVaR 97.5   EUR {risk.cvar_975:,.0f}")`, `Book NPV    EUR 9,133\nVaR 95      EUR 11,715\nVaR 99      EUR 15,790\nCVaR 97.5   EUR 15,897`, "python", distributionChart())}
    <div class="next-card"><span>Next</span><a href="#/guide/concepts">Understand QuantVolt's core concepts →</a></div>
  `},
  concepts: {title:"Core concepts", description:"The domain vocabulary shared by every QuantVolt module.", body:`
    <h2 id="value-objects">Immutable value objects</h2><p>Commodities, delivery periods, curves, instruments and results are frozen dataclasses. Validation occurs at construction and caller inputs are never mutated.</p>${codeBlock(`period = qv.DeliveryPeriod(2026, 12)\nttf = qv.BUILT_IN_COMMODITIES["TTF"]\nnode = qv.CurveNode(period, 36.85, "observed")`, `DeliveryPeriod(year=2026, month=12)`)}
    <h2 id="facade">Curated facade</h2><p>Common domain objects and workflows are available from <code>quantvolt</code>. Specialized numerical and statistical functions stay in subpackages such as <code>quantvolt.numerics</code> and <code>quantvolt.stats</code>.</p>
    <h2 id="errors">Validation and errors</h2><p>Invalid inputs raise a subclass of <code>EnergyQuantError</code> before computation. Common types include <code>ValidationError</code>, <code>InsufficientDataError</code>, <code>MissingTenorError</code> and <code>ArbitrageError</code>.</p>
    <h2 id="serialization">Serialization</h2>${codeBlock(`payload = curve.to_dict()\nrestored = qv.ForwardCurve.from_dict(payload)\nassert restored == curve`, `✓ exact JSON-friendly round trip`)}
  `},
  curves: {title:"Forward curves", description:"Construct, inspect and validate energy forward curves.", body:`
    <h2 id="construction">Curve construction</h2><p><code>CurveBuilder</code> accepts observed instrument prices, fills missing monthly tenors and records whether each node was observed or interpolated.</p>${codeBlock(`result = qv.CurveBuilder().build(\n    commodity=ttf,\n    market_date=date(2026, 7, 15),\n    instruments=observed,\n    interpolation="piecewise_linear",\n    storage_cost=0.50,\n)`, `4 nodes · 2 observed · 2 interpolated\nmax reprice residual: 0.0000`, "python", miniCurve())}
    <h2 id="interpolation">Interpolation methods</h2><table><thead><tr><th>Method</th><th>Minimum quotes</th><th>Use</th></tr></thead><tbody><tr><td><code>piecewise_flat</code></td><td>1</td><td>Sparse operational assumptions</td></tr><tr><td><code>piecewise_linear</code></td><td>2</td><td>Default transparent interpolation</td></tr><tr><td><code>cubic_spline</code></td><td>4</td><td>Smooth well-observed term structures</td></tr></tbody></table>
    <h2 id="arbitrage">Cost-of-carry checks</h2><p><code>check_arbitrage</code> (and its <code>ArbitrageChecker</code> alias) validates whether a curve's calendar spreads are consistent with a declared per-month cost of carry: it flags each consecutive pair whose near-to-far decline is steeper than <code>storage_cost</code> can explain. This is a carry-consistency check, not a proof of tradable arbitrage &mdash; convenience yield, storage constraints and deliverability can justify a backwardated or non-monotonic curve. Violations are returned as <code>ArbitrageWarning</code> data, so policy decisions stay with the caller; the curve is never altered.</p>
    <h2 id="models">Stochastic curve models</h2><p>Use <code>SchwartzSmithParams</code> for two-factor short/long dynamics, or <code>MultifactorForwardModel</code> for correlated multi-commodity forward simulation.</p>
  `},
  pricing: {title:"Pricing derivatives", description:"Create and value linear, optional and structured energy contracts.", body:`
    <p>Every high-level pricer accepts typed domain objects, validates complete curve coverage, and returns an immutable result. Start with the contract family you need:</p>
    <div class="contract-map"><a data-section="futures" href="#/guide/pricing"><b>Futures</b><code>price_futures</code></a><a data-section="forwards" href="#/guide/pricing"><b>Forwards</b><code>price_futures</code></a><a data-section="swaps" href="#/guide/pricing"><b>Swaps</b><code>price_swap</code></a><a data-section="vanilla" href="#/guide/pricing"><b>Vanilla options</b><code>price_vanilla_option</code></a><a data-section="exotics" href="#/guide/pricing"><b>Exotics</b><code>price_asian · barrier · lookback</code></a><a data-section="tolling" href="#/guide/pricing"><b>Structured assets</b><code>tolling · transmission rights</code></a></div>
    <h2 id="futures">Exchange-traded futures</h2><p>A <code>FuturesContract</code> is standardized, margined and financially settled by default. Positive notional represents a long position.</p>${codeBlock(`period = qv.DeliveryPeriod(2026, 12)\nfuture = qv.FuturesContract(\n    commodity=ttf,\n    delivery_period=period,\n    contract_price=35.00,\n    notional=5_000.0,\n    granularity=qv.Granularity.MONTHLY,\n    settlement_type=qv.SettlementType.FINANCIAL,\n)\npriced = qv.price_futures(\n    future, ttf_curve, valuation_date, discount_curve\n)`, `FuturesPricingResult(\n  npv=9,133.00,\n  delta=4,950.00\n)`)}
    <p>The pricing identity is <code>DF × (forward − contract price) × notional</code>. An expired delivery period raises <code>ExpiredContractError</code>; missing curve coverage raises <code>MissingTenorError</code>.</p>
    <h2 id="forwards">Bilateral forwards</h2><p>Forwards share the linear pricing formula but add physical settlement and counterparty identity. This distinction is retained for settlement and credit-risk workflows.</p>${codeBlock(`forward = qv.ForwardContract(\n    commodity=ttf,\n    delivery_period=period,\n    contract_price=34.50,\n    notional=5_000.0,\n    settlement_type=qv.SettlementType.PHYSICAL,\n    counterparty="Utility BV",\n)\npriced = qv.price_futures(\n    forward, ttf_curve, valuation_date, discount_curve,\n    settlement_lag_days=2,\n)`, `NPV          €11,608\nDelta         4,950\nSettlement    physical\nCounterparty  Utility BV`)}
    <h2 id="swaps">Fixed-for-floating swaps</h2><p>A swap spans an explicit <code>DeliverySchedule</code>. QuantVolt values every period and returns total NPV, per-period forward delta and interest-rate rho.</p>${codeBlock(`schedule = qv.DeliverySchedule((\n    qv.DeliveryPeriod(2026, 10),\n    qv.DeliveryPeriod(2026, 11),\n    qv.DeliveryPeriod(2026, 12),\n))\nswap = qv.SwapContract(\n    commodity=ttf,\n    fixed_rate=34.00,\n    floating_index="TTF_MONTH_AHEAD",\n    notional=2_000.0,\n    schedule=schedule,\n)\npriced = qv.price_swap(swap, ttf_curve, discount_curve)`, `SwapPricingResult(\n  npv=4,902.14,\n  delta=(1,986.2, 1,981.4, 1,976.8),\n  rho=-3.27\n)`)}
    <h2 id="vanilla">Vanilla options</h2><p>European calls and puts use Black–76 and return the full Greek set.</p>${codeBlock(`option = qv.price_vanilla_option(qv.VanillaOptionRequest(\n    option_type="call", forward=36.85, strike=38.0,\n    sigma=0.55, time_to_expiry=0.4,\n    discount_factor=0.99, notional=10_000,\n))`, `premium  €45,663\ndelta     5,288\ngamma       293\nvega     82,904`)}
    <h2 id="caps-floors">Caps and floors</h2><p><code>price_cap_floor</code> prices a strip over multiple forwards. The result exposes aggregate premium and the contribution of every caplet or floorlet, so tenor-level attribution is preserved.</p>
    <h2 id="exotics">Asian, barrier and lookback options</h2><table><thead><tr><th>Contract</th><th>Available method</th><th>Entry point</th></tr></thead><tbody><tr><td>Arithmetic/geometric Asian</td><td>Turnbull–Wakeman, Kemna–Vorst, seeded Monte Carlo</td><td><code>price_asian</code></td></tr><tr><td>Knock-in / knock-out barrier</td><td>Analytic barrier formula</td><td><code>price_barrier</code></td></tr><tr><td>Fixed/floating lookback</td><td>Analytic lookback formula</td><td><code>price_lookback</code></td></tr></tbody></table>
    <h2 id="spread-options">Spread options</h2>${codeBlock(`request = qv.SpreadOptionRequest(\n    forward1=92.0, forward2=73.70, strike=4.0,\n    sigma1=0.38, sigma2=0.52, correlation=0.61,\n    time_to_expiry=0.5, discount_factor=0.98,\n    notional=1_000.0,\n)\nresult = qv.price_spread_option(request)`, `premium       €17,939.37\nmodel         Kirk\nlong-leg Δ    754.97\nshort-leg Δ  -658.67`)}<p>Kirk is used for non-zero strikes; the zero-strike case collapses to Margrabe.</p>
    <h2 id="spreads">Physical and refining spreads</h2>${codeBlock(`spark = qv.spark_spread(\n    power_curve, gas_curve, heat_rate=2.0, variable_cost=3.5\n)\nclean = qv.clean_spread(\n    spark, eua_curve, emissions_intensity=0.37\n)\nprint(clean.per_period)`, `{DeliveryPeriod(2026, 12): -14.06}  # EUR/MWh`)}<p>Related helpers cover dark, forward, calendar, basis and configurable crack spreads, plus implied heat rate.</p>
    <h2 id="tolling">Tolling agreements</h2><p><code>price_tolling_agreement</code> values a thermal plant as a strip of clean-spread options. It requires power, fuel and EUA curves, a volatility surface, a correlation matrix, plant conversion parameters, schedule and discount curve.</p>
    <h2 id="rights">Transmission and pipeline rights</h2><p><code>value_transport_right</code> values directional or bidirectional transport after tariffs, losses and capacity constraints. Both <code>TransmissionRight</code> and <code>PipelineRight</code> retain route and direction metadata.</p>
    <h2 id="implied-vol">Implied volatility and surfaces</h2><p>Recover Black–76 volatility from premiums with <code>implied_vol</code>, classify moneyness, estimate cumulative historical volatility and construct a <code>VolatilitySurface</code> from tenor/moneyness quotes.</p>
  `},
  "portfolio-risk": {title:"Portfolio valuation and risk", description:"Build every instrument and position explicitly, value the book, then measure its risk.", body:`
    <p>Full runnable script: <code>site/examples/verify_portfolio_risk.py</code> — every output below is pasted verbatim from a run of it.</p>
    <h2 id="instruments">1. Create the instruments</h2><p>Instrument IDs do not live on the contracts. Contracts describe economics; stable book identity is assigned by <code>Position</code>.</p>${codeBlock(`import quantvolt as qv\nfrom datetime import date\n\nttf = qv.BUILT_IN_COMMODITIES["TTF"]\npower = qv.BUILT_IN_COMMODITIES["EEX_PHELIX_DE"]\n\nperiod = qv.DeliveryPeriod(2026, 12)\n\ngas_future = qv.FuturesContract(\n    commodity=ttf,\n    delivery_period=period,\n    contract_price=35.00,\n    notional=5_000.0,\n)\n\npower_schedule = qv.DeliverySchedule((period,))\npower_swap = qv.SwapContract(\n    commodity=power,\n    fixed_rate=82.00,\n    floating_index="EPEX_SPOT_DE",\n    notional=1_000.0,\n    schedule=power_schedule,\n)`, `2 instruments created\nTTF future       Dec-26 · 5,000 MWh\nPower swap       Dec-26 · 1,000 MWh`)}
    <h2 id="positions">2. Create positions with stable IDs</h2><p><code>position_id</code> is the join key used by valuation, realized settlement, reporting and caller-owned interval data. Tags are an immutable tuple of caller-defined strings.</p>${codeBlock(`gas_position = qv.Position(\n    instrument=gas_future,\n    position_id="gas-future-dec26",\n    tags=("desk:gas", "strategy:winter-hedge"),\n)\npower_position = qv.Position(\n    instrument=power_swap,\n    position_id="power-swap-dec26",\n    tags=("desk:power", "strategy:generation-hedge"),\n)\n\nportfolio = qv.Portfolio(positions=(\n    gas_position,\n    power_position,\n))`, `Portfolio(2 positions)\n├─ gas-future-dec26   desk:gas\n└─ power-swap-dec26   desk:power`)}
    <h2 id="market-data">3. Provide market data</h2>${codeBlock(`# Three observed quotes per curve, piecewise-linear (full records in the script):\n#   TTF            Oct-26 31.40   Dec-26 36.85   Mar-27 34.10\n#   EEX_PHELIX_DE  Oct-26 88.40   Dec-26 92.00   Mar-27 85.30\nttf_curve = qv.CurveBuilder().build(ttf, date(2026, 7, 15), ttf_quotes,\n    interpolation="piecewise_linear").curve\npower_curve = qv.CurveBuilder().build(power, date(2026, 7, 15), power_quotes,\n    interpolation="piecewise_linear").curve\n\ndiscounting = qv.DiscountCurve(\n    reference_date=date(2026, 7, 15),\n    tenors=(date(2026, 7, 16), date(2027, 12, 31)),\n    factors=(1.0, 0.96),\n)\nmarket = qv.MarketData(\n    forward_curves={\n        "TTF": ttf_curve,\n        "EEX_PHELIX_DE": power_curve,\n    },\n    discount_curve=discounting,\n    valuation_date=date(2026, 7, 15),\n)`, `MarketData\n  valuation date  2026-07-15\n  forward curves  TTF, EEX_PHELIX_DE\n  discount curve  covered`)}
    <h2 id="valuation">4. Value the portfolio</h2>${codeBlock(`valuation = qv.value_portfolio(portfolio, market)\n\nfor item in valuation.priced:\n    print(item.position.position_id, item.npv)`, `gas-future-dec26    €9,133\npower-swap-dec26    €9,874\n──────────────────────────\ntotal NPV           €19,007`)}<div class="result-grid"><div><small>Priced</small><strong>2</strong></div><div><small>Unpriced</small><strong>0</strong></div><div><small>Total NPV</small><strong>€19,007</strong></div></div><p>The result separates <code>priced</code> and <code>unpriced</code> positions. PPAs and realized power hedges stay unpriced unless you register a forward-looking valuation pricer; this prevents realized cash flow from being mislabeled as NPV.</p>
    <h2 id="risk-engine">5. Compute portfolio risk</h2>${codeBlock(`import numpy as np\n\nscenarios = np.random.default_rng(42).normal(\n    loc=0.0, scale=1.5, size=(10_000, 2)\n)\nrisk = qv.RiskEngine().compute_risk(\n    list(valuation.priced), scenarios\n)`, `VaR 95       €12,541\nVaR 99       €17,814\nCVaR 97.5    €18,007`, "python", distributionChart())}
    <p><strong>The scenario matrix, precisely.</strong> Rows are scenarios; each row produces one portfolio P&amp;L via <code>pnl_row = row &middot; delta_vector</code>. Columns are risk factors: one per cell of the aggregated <code>DeltaMatrix</code>, flattened row-major (commodities sorted lexicographically, delivery periods sorted chronologically). <code>n_factors</code> must equal <code>n_commodities &times; n_periods</code>, or <code>compute_risk</code> raises a <code>ValidationError</code> naming both dimensions &mdash; this book has 2 commodities (TTF, EEX_PHELIX_DE) &times; 1 period (Dec-26) = 2 columns. Shocks are <strong>absolute</strong>, applied per unit of delta (<code>pnl = delta &times; shock</code>); a matrix of relative moves must be pre-scaled by reference prices before the call. Loss is <code>L = -pnl</code>; VaR/CVaR are upper-tail quantiles of L. A position with an empty delta map or a non-finite NPV is excluded into <code>exclusion_report</code>, not silently dropped. <code>apply_scenario</code> uses a different, relative-shock convention (<code>delta &times; reference_price &times; shock</code>) &mdash; the two methods are not interchangeable inputs.</p>
    <h2 id="risk-family">Choose a risk method</h2><table><thead><tr><th>Function</th><th>Method</th><th>Best for</th></tr></thead><tbody><tr><td><code>RiskEngine.compute_risk</code></td><td>Historical/scenario delta P&amp;L</td><td>Fast book-level risk</td></tr><tr><td><code>parametric_var</code></td><td>Linear-normal or delta-gamma</td><td>Analytic reporting</td></tr><tr><td><code>monte_carlo_var</code></td><td>Full revaluation</td><td>Non-linear positions</td></tr><tr><td><code>cash_flow_at_risk</code></td><td>Operational scenarios</td><td>Physical assets and PPAs</td></tr><tr><td><code>credit_var</code></td><td>Default and recovery</td><td>Counterparty exposure</td></tr></tbody></table>
    <h2 id="stress">6. Apply named stress scenarios</h2>${codeBlock(`stress = qv.RiskEngine().apply_scenario(\n    list(valuation.priced),\n    "European Gas Crisis 2022",\n)\nprint(stress.total_pnl)`, `scenario     European Gas Crisis 2022\ntotal P&L    +€727,461`)}<p>The catalogue also includes Cold Snap Winter, Mild Winter Demand Slump and Carbon Price Shock. Custom <code>ScenarioShock</code> values may target a single period or an entire commodity.</p>
  `},
  ppa: {title:"PPAs and interval settlement", description:"Settle physical generation, imbalance and typed hedges without hiding assumptions.", body:`
    <h2 id="contract">Define the contract</h2>${codeBlock(`contract = qv.PpaContract(\n    contract_id="plant-ppa", bidding_zone="DE-LU",\n    fixed_price_per_mwh=70.0,\n    start_utc=start, end_utc=end,\n    volume_basis=qv.PpaVolumeBasis.BASELOAD,\n)`, `PpaContract(contract_id='plant-ppa', bidding_zone='DE-LU', …)`)}
    <h2 id="settlement">Settle caller-owned data</h2>${codeBlock(`ledger = qv.settle_ppa_frame(\n    contract, intervals, columns=columns, hedges=[floor]\n)`, `contracted  10.0 MWh\nmetered      8.0 MWh\nshortfall    -2.0 MWh\nnet cashflow €480.00`)}
    <h2 id="time-utc">Time is UTC in, local is the caller's job</h2><p>Every delivery interval is a half-open <code>[start_utc, end_utc)</code> pair on <code>PowerDeliveryInterval</code>, and both bounds must be timezone-aware and expressed in exactly UTC. The settlement engine never guesses a time zone, never resamples, and never repairs the clock. A naive datetime, or one carrying a non-zero offset such as CEST <code>+02:00</code>, is rejected at construction.</p>
    <div class="admonition warning"><b>Daylight saving is handled by requiring UTC input</b><p>Local wall-clock labels are not safe on a DST boundary: on the autumn fall-back the local hour repeats, and on the spring forward one local hour does not exist. QuantVolt settles on UTC intervals only, so a 23-hour spring day and a 25-hour autumn day simply produce fewer or more UTC intervals for the same civil day &mdash; the caller maps local delivery days to UTC, and the interval count follows automatically.</p></div>
    <p><code>settle_ppa_frame</code> additionally rejects duplicate interval starts, unsorted starts, and (with the default <code>require_contiguous=True</code>) any gap or overlap between one interval's end and the next interval's start. Resolution is whatever the caller's stamps encode: hourly, half-hourly and quarter-hourly all use the same type, and durations must be a whole number of minutes. Nomination calibration additionally requires one uniform interval duration across the calibration window, and <code>apply_ppa_nomination</code> rejects any evaluation row whose duration differs from the calibrated duration.</p>
    <p>QuantVolt supports three volume bases, selected by <code>PpaVolumeBasis</code>: <code>BASELOAD</code>, <code>SHAPED</code> and <code>PAY_AS_PRODUCED</code>. The engine does not shape volume itself &mdash; baseload and shaped differ only in the per-interval <code>contracted_mwh</code> the caller supplies (a flat value for baseload, a profile for shaped). <code>PAY_AS_PRODUCED</code> enforces that <code>contracted_mwh</code> equals <code>metered_generation_mwh</code> on every interval, so a producer contracts exactly what it generates. All settlement volumes are energy in <strong>MWh</strong> and all prices are <strong>EUR/MWh</strong>; <code>net_cashflow</code> and every signed ledger component are in EUR.</p>
    <div class="admonition warning"><b>Explicit imbalance policy</b><p>Physical settlement requires shortfall and excess prices. Using spot as a proxy requires the explicit <code>USE_SPOT</code> policy.</p></div>
    <h2 id="hedges">Settle typed power hedges</h2><p>Typed floors, caps, swaps and collars can be settled alongside the PPA. Their IDs provide contract-level attribution and prevent cash flows from being hidden in a generic column.</p>${codeBlock(`floor = qv.PowerHedgeContract(\n    hedge_id="revenue-floor",\n    hedge_type=qv.PowerHedgeType.FLOOR,\n    position=qv.PowerHedgePosition.LONG,\n    start_utc=contract.start_utc,\n    end_utc=contract.end_utc,\n    volume_mwh=10.0,\n    strike_per_mwh=60.0,\n    allocated_premium_per_mwh=2.0,\n)\nhedge_detail = qv.settle_power_hedges_frame(\n    [floor], intervals,\n    interval_start_column="from",\n    interval_end_column="to",\n    spot_price_column="day_ahead_eur_mwh",\n)`, `revenue-floor\n  intrinsic payoff  €0.00\n  premium          -€20.00\n  net cash flow    -€20.00`)}
    <h2 id="nomination">Calibrate without look-ahead</h2>${codeBlock(`fit = qv.calibrate_ppa_nomination(\n    contract, calibration_data,\n    calibration_end_utc=cutoff,\n    capacity_mwh_per_interval=2.5,\n    columns=nomination_columns,\n    objective=qv.PpaNominationObjective.MAX_MEAN_MINUS_CFAR,\n    risk_aversion=1.0, confidence_level=0.95,\n)\nevaluation = qv.apply_ppa_nomination(\n    fit, evaluation_data,\n    interval_start_column="from",\n    interval_end_column="to",\n)`, `selected nomination  1.75 MWh / interval\nmean cash flow       €118.40\nCFaR 95              €37.10\ncalibration cutoff   enforced`)}
  `},
  assets: {title:"Physical assets", description:"Optimize dispatch and storage under technical constraints and uncertain prices.", body:`
    <h2 id="plant">Thermal plant dispatch</h2>${codeBlock(`result = qv.dispatch_deterministic(\n    power_prices, fuel_prices, carbon_prices, plant\n)\nprint(result.total_value)`, `total value    €127,480\nrunning hours  13 / 24\nstarts         2`, "python", dispatchChart())}
    <h2 id="stochastic">Stochastic dispatch</h2><p><code>dispatch_value</code> supports LSM and lattice valuation, with diagnostics for regression conditioning and boundary behavior.</p>
    <h2 id="storage">Gas storage</h2><p><code>storage_intrinsic</code> optimizes against a known curve; see the <a href="#/guide/tutorial-storage">storage tutorial</a> for the extrinsic-value honesty caveat (standard error vs. estimate) before reporting any <code>storage_value</code> figure.</p>
    <h2 id="governance">Long-dated governance</h2><p>Benchmarking, horizon division, time aggregation and VaR applicability guards make approximation choices visible in results.</p>
  `},
  hedging: {title:"Hedging incomplete markets", description:"Estimate hedge ratios and quantify the risk left behind.", body:`
    <h2 id="variance">Variance-minimizing hedge</h2><p><code>variance_min_hedge(sigma_hh, sigma_ht)</code> takes hedge-instrument return covariance matrices and returns a plain <code>numpy.ndarray</code> of ratios solving <code>Σ_hh &middot; h* = Σ_ht</code> &mdash; there is no <code>.hedge_ratio</code> attribute and no negative sign in the formula.</p>${codeBlock(`sigma_hh = np.array([[4.00, 0.30], [0.30, 2.25]])  # 2 hedge instruments\nsigma_ht = np.array([1.80, 0.45])                  # hedge-vs-target return covariance\nratios = qv.variance_min_hedge(sigma_hh, sigma_ht)\nprint(ratios)`, `[0.4394, 0.1414]`)}
    <h2 id="cross">Cross-commodity hedge</h2><p><code>linear_cross_hedge</code> handles basis risk when the exposure and traded hedge are different commodities.</p>
    <h2 id="ppa-nomination">PPA nominations</h2><p>Calibration and walk-forward functions separate fitting from evaluation, enforce time cutoffs and support mean-minus-CFaR objectives.</p>
  `},
  statistics: {title:"Energy time-series statistics", description:"Test data properties before selecting a pricing or risk model.", body:`
    <h2 id="descriptive">Descriptive analysis</h2><p>Compute returns, volatility, skew, kurtosis, drawdowns and robust summaries over Polars series.</p>
    <h2 id="stationarity">Stationarity</h2>${codeBlock(`result = qv.test_stationarity(\n    prices, contract_expiry=expiry, observation_dates=dates,\n)\nprint(result.adf_p_value, result.kpss_p_value, result.is_stationary)`, `StationarityResult\n  ADF p-value, KPSS p-value\n  is_stationary requires ADF to reject and KPSS to fail to reject`)}
    <h2 id="mean-reversion">Mean reversion</h2>${codeBlock(`fit = fit_ou(prices, dt=1 / 365)\nprint(fit.half_life)`, `18.4 days`)}
    <h2 id="normality">Normality and correlation</h2><p>Normality tests, Pearson/Spearman correlations and rolling correlation diagnostics support distribution and dependency choices.</p>
  `},
  data: {title:"Optional data adapters", description:"Fetch external observations without coupling analytics to I/O.", body:`
    <h2 id="providers">Providers</h2><table><thead><tr><th>Adapter</th><th>Data</th></tr></thead><tbody><tr><td>ENTSO-E</td><td>European electricity prices, load and generation</td></tr><tr><td>ENTSOG</td><td>Gas transmission fundamentals</td></tr><tr><td>SMARD</td><td>German power prices and fundamentals</td></tr><tr><td>Netztransparenz</td><td>German reBAP imbalance prices</td></tr><tr><td>Open-Meteo</td><td>Weather observations and forecasts</td></tr></tbody></table>
    <h2 id="fetch">Fetch and map</h2>${codeBlock(`from quantvolt.data import NetztransparenzSource, attach_rebap_prices\nrebap = NetztransparenzSource().rebap(start, end)\nsettlement_data = attach_rebap_prices(caller_data, rebap)`, `96 quarter-hour intervals matched\n0 missing · 0 duplicates`)}
    <h2 id="snapshots">Reproducible snapshots</h2><p><code>snapshot</code> and <code>restore</code> serialize supported domain data for replay. Analytics functions remain independent of providers.</p>
  `},
  validation: {title:"External validation evidence", description:"Closed-form and Monte Carlo pricers checked against QuantLib 1.43, plus internal MC-convergence checks.", body:`
    <p>Internal unit/property tests cannot rule out a shared blind spot in this codebase's own mathematics. This page compares QuantVolt's pricers against an <strong>independent, third-party reference implementation</strong> &mdash; QuantLib 1.43 &mdash; using checked-in golden fixtures, plus internal analytic-vs-Monte-Carlo convergence checks. This is validation of the <em>pricing kernels</em>, not of the whole library or of any specific PPA/portfolio workflow built on them; nothing here changes <code>src/quantvolt/</code> behavior.</p>
    <div class="admonition note"><b>Anti-drift check</b><p>Every number below is pasted verbatim from an actual run of <code>site/examples/verify_validation.py</code>, which recomputes a curated subset of the checked-in fixtures with <strong>no reference library installed</strong>. If a future change makes the script print different numbers, this page has drifted and must be regenerated.</p></div>
    <h2 id="black76">Black-76: premium, Greeks, implied vol</h2><p>764 cases over <code>F/K &isin; {0.5, 0.8, 0.95, 1.0, 1.05, 1.25, 2.0}</code> &times; <code>&sigma; &isin; {0.05, 0.20, 0.55, 1.00}</code> &times; <code>T &isin; {0.02, 0.25, 1.0, 3.0}</code> &times; <code>DF &isin; {1.0, 0.97, 0.85}</code>, calls and puts, plus degenerate <code>&sigma;=0</code>/<code>T=0</code> edges (<code>tests/validation/fixtures/black76.json</code>, generated by <code>scripts/fixtures/gen_black76_fixtures.py</code> against QuantLib 1.43 on 2026-07-18). Two representative cases and both degenerate edges:</p>
    <table><thead><tr><th>Case</th><th>Reference (QuantLib 1.43)</th><th>QuantVolt</th><th>Diff</th><th>Tolerance</th><th>Seed</th></tr></thead><tbody>
      <tr><td>call ATM &sigma;=0.20 T=1.0 DF=0.97 &mdash; premium</td><td>7.726600432</td><td>7.726600432</td><td>0.000e+00</td><td>rel 1e-9</td><td>n/a</td></tr>
      <tr><td>call ATM &mdash; delta</td><td>0.5236330022</td><td>0.5236330022</td><td>1.110e-16</td><td>rel 1e-9</td><td>n/a</td></tr>
      <tr><td>call ATM &mdash; gamma</td><td>0.01925219855</td><td>0.01925219855</td><td>3.469e-18</td><td>rel 1e-9</td><td>n/a</td></tr>
      <tr><td>call ATM &mdash; vega</td><td>38.50439711</td><td>38.50439711</td><td>0.000e+00</td><td>rel 1e-9</td><td>n/a</td></tr>
      <tr><td>call ATM &mdash; implied vol round-trip</td><td>0.2</td><td>0.2</td><td>5.274e-16</td><td>rel 1e-7</td><td>n/a</td></tr>
      <tr><td>put ATM &sigma;=0.20 T=1.0 DF=0.97 &mdash; premium</td><td>7.726600432</td><td>7.726600432</td><td>0.000e+00</td><td>rel 1e-9</td><td>n/a</td></tr>
      <tr><td>put ATM &mdash; delta</td><td>-0.4463669978</td><td>-0.4463669978</td><td>1.110e-16</td><td>rel 1e-9</td><td>n/a</td></tr>
      <tr><td>degenerate &sigma;=0 (F=100,K=80,T=1,DF=1)</td><td>discounted intrinsic = 20</td><td>20</td><td>0</td><td>exact identity</td><td>n/a</td></tr>
      <tr><td>degenerate T=0 (F=100,K=80,&sigma;=0.20,DF=1)</td><td>discounted intrinsic = 20</td><td>20</td><td>0</td><td>exact identity</td><td>n/a</td></tr>
    </tbody></table>
    <p><strong>Tolerance rationale</strong> (fixture, verbatim): premium/delta/gamma/vega rel 1e-9 because both are closed forms &mdash; the residual is only the two normal-CDF implementations' difference; implied vol rel 1e-7 is root-finder termination. Degenerate cases assert the discounted-intrinsic identity (<code>black76.py:88-92</code>) rather than a QuantLib inversion.</p>
    <h2 id="capfloor">Cap/floor strip: caplet-by-caplet</h2><p>QuantLib's interest-rate cap machinery is <strong>not used</strong> as the reference (Ibor forwards and accrual day-counts make it incomparable to an energy cap on delivery-period forwards); each caplet is priced individually via QuantLib <code>blackFormula</code> with its own forward/&sigma;/T/DF (<code>tests/validation/fixtures/capfloor.json</code>, 3 strips / 24 caplets). One 6-caplet strip (strike 50, notional 1000) in full:</p>
    <table><thead><tr><th>Case</th><th>Reference</th><th>QuantVolt</th><th>Diff</th><th>Tolerance</th></tr></thead><tbody>
      <tr><td>caplet[0] F=52.0 &sigma;=0.60 T=0.08</td><td>4517.459195</td><td>4517.459195</td><td>0.000e+00</td><td>rel 1e-9</td></tr>
      <tr><td>caplet[1] F=48.0 &sigma;=0.55 T=0.17</td><td>3459.688772</td><td>3459.688772</td><td>0.000e+00</td><td>rel 1e-9</td></tr>
      <tr><td>caplet[2] F=45.0 &sigma;=0.50 T=0.25</td><td>2596.488389</td><td>2596.488389</td><td>3.183e-12</td><td>rel 1e-9</td></tr>
      <tr><td>caplet[3] F=47.0 &sigma;=0.45 T=0.33</td><td>3556.624178</td><td>3556.624178</td><td>6.821e-12</td><td>rel 1e-9</td></tr>
      <tr><td>caplet[4] F=55.0 &sigma;=0.40 T=0.42</td><td>8066.936741</td><td>8066.936741</td><td>0.000e+00</td><td>rel 1e-9</td></tr>
      <tr><td>caplet[5] F=60.0 &sigma;=0.38 T=0.50</td><td>11804.264053</td><td>11804.26405</td><td>0.000e+00</td><td>rel 1e-9</td></tr>
      <tr><td><strong>strip (additivity check)</strong></td><td>34001.461326</td><td>34001.46133</td><td>7.276e-12</td><td>rel 1e-9</td></tr>
    </tbody></table>
    <h2 id="spread">Spread options: Kirk / Margrabe</h2><p>Mapping (fixture <code>notes</code>, verbatim): each leg's process has dividend yield = risk-free rate (q=r) so the process spot equals the forward, matching QuantVolt's forward-based inputs. 120 cases over <code>K &isin; {0, 2.5, 5, 10}</code> &times; <code>&rho; &isin; {-0.5, 0, 0.3, 0.61, 0.9}</code> &times; <code>T &isin; {0.25, 0.5, 1.0}</code> (<code>tests/validation/fixtures/spread.json</code>):</p>
    <table><thead><tr><th>Case</th><th>Reference</th><th>QuantVolt</th><th>Diff</th><th>Tolerance</th></tr></thead><tbody>
      <tr><td>Margrabe (K=0 collapse) F1=45 F2=30 &rho;=-0.5 T=0.25</td><td>15.614354483</td><td>15.61435448</td><td>0.000e+00</td><td>rel 1e-9</td></tr>
      <tr><td>Kirk K=2.5 F1=45 F2=30 &rho;=-0.5 T=0.25</td><td>13.618859591</td><td>13.61885959</td><td>3.553e-15</td><td>rel 1e-9</td></tr>
    </tbody></table>
    <h2 id="storage-blocked">Gas storage vs cmdty-storage &mdash; BLOCKED (environment)</h2><p><code>tests/validation/fixtures/storage.json</code> does not exist: <code>scripts/fixtures/gen_storage_fixtures.py</code> requires cmdty-storage's pythonnet/.NET runtime, unavailable in this implementation environment, and reports BLOCKED rather than fabricate a reference value. Tolerances were instead sized from an internal QuantVolt-only <strong>multi-method</strong> study (no reference library), including an exact grid-free linear-programming cross-check of the intrinsic DP: intrinsic rel 0.5% (valid only at <code>grid_steps &ge; 200</code> &mdash; on misaligned cases the DP-vs-LP discretisation gap is &lt;0.3% at 200 but ~2% at 50), extrinsic rel 5% for an intrinsic-anchored case (a material-extrinsic flat-curve total is heavy-tailed and needs an absolute <code>k&middot;SE</code> band instead). See the grid-refinement study in the repository's internal validation notes for the full 5-case design.</p>
    <h2 id="mc-convergence">Analytic-vs-Monte-Carlo convergence</h2><p><code>tests/validation/test_mc_convergence.py</code> checks the Rust Monte Carlo engine against QuantVolt's <em>own</em> closed forms (not QuantLib &mdash; there is no independent MC reference). Every test is seeded with tolerance <code>k &times; reported standard error</code>:</p>
    <table><thead><tr><th>Case</th><th>Closed form</th><th>Monte Carlo</th><th>Diff</th><th>Tolerance</th><th>Seed</th></tr></thead><tbody>
      <tr><td>Black-76 vanilla vs <code>asian_monte_carlo(averaging_points=1)</code>, F=K=100 &sigma;=0.20 T=1.0 DF=0.97, 200,000 paths</td><td>7.726600</td><td>7.716017</td><td>0.0106</td><td>5&times;SE = 0.1427</td><td>42</td></tr>
    </tbody></table>
    <p>The full suite also covers Margrabe vs correlated-forwards MC at K=0, Kirk approximation-bias vs the same MC, Turnbull-Wakeman vs discrete arithmetic-Asian MC, MC put-call parity, and storage extrinsic &rarr; 0 as &sigma; &rarr; 1e-4.</p>
    <h2 id="caveats">Honest caveats and known limitations</h2><ul>
      <li><strong>cmdty-storage cross-check is BLOCKED on this environment.</strong> The storage kernels have not been checked against an independent third-party implementation &mdash; only against internal methods: an exact grid-free LP cross-check of the intrinsic DP (a second method), grid-refinement convergence, and property tests. Two internal methods agreeing shows consistency, not agreement with an external engine.</li>
      <li><strong>Storage parameter-mapping risks</strong> if a future cmdty-storage run is added: QuantVolt's DP is undiscounted; monthly-vs-daily granularity biases cmdty-storage &ge; QuantVolt; rate units need days-in-month scaling; the loss convention is documented at <code>storage.py:313-331</code>; <code>carry_cost</code> has no cmdty-storage equivalent.</li>
      <li><strong>Haug (2007) secondary spread-option check is BLOCKED</strong> &mdash; the physical book was unavailable at implementation time; no table value was recalled from memory.</li>
      <li><strong>Barrier and lookback options have no analytic-vs-Monte-Carlo cross-check.</strong> The continuous-monitoring closed forms need a Broadie-Glasserman-Kou discretisation correction to be comparable to a discrete-monitoring Monte Carlo; this is a recorded limitation, not a silent gap.</li>
      <li><strong>theta/rho are compared via finite difference of the QuantLib premium</strong>, not an independent closed form, hence their looser rel 1e-6 tolerance.</li>
      <li><strong>This page covers pricing kernels only</strong> &mdash; not PPA settlement accounting, portfolio aggregation, or risk-engine scenario logic.</li>
    </ul>
    <h2 id="regenerate">Regenerating the fixtures</h2><p>Reference libraries are never a runtime or CI dependency (PEP 735 <code>[dependency-groups] validation</code>, never <code>[project.optional-dependencies]</code>).</p>${codeBlock(`uv sync --group validation   # installs QuantLib>=1.34\npython scripts/fixtures/gen_black76_fixtures.py\npython scripts/fixtures/gen_capfloor_fixtures.py\npython scripts/fixtures/gen_spread_fixtures.py\n\n# cmdty-storage fixture -- requires a .NET/pythonnet-capable environment\npython scripts/fixtures/gen_storage_fixtures.py`, `CI never installs the validation dependency group\nand never runs a generator script.`, "shell")}
    <p>Full detail, including every fixture's complete provenance block, lives in <a href="https://github.com/nimabahrami/quantvolt/blob/main/docs/validation.md">docs/validation.md</a>.</p>
  `},
  conventions: {title:"Units and conventions", description:"Package-wide units, signs, time handling and risk conventions.", body:`
    <h2 id="units">Native quotation per built-in commodity (all 14)</h2><p>Built-in commodities carry their native venue quotation, not a convenience unit. <code>quantvolt.models.units.PriceUnit</code> validates every <code>price_unit</code> eagerly; <code>convert_price</code> reconciles hubs quoted in different units onto one consistent basis before cross-commodity analytics. Citation status records whether the exact price-unit wording was captured verbatim from the exchange source (<code>docs/market_conventions.json</code>).</p><table><thead><tr><th>Market / hub</th><th>Built-in ID</th><th>Exchange</th><th>Native unit</th><th>Currency</th><th>Citation status</th></tr></thead><tbody>
      <tr><td>Dutch TTF gas</td><td><code>TTF</code></td><td>ICE_ENDEX</td><td>EUR/MWh</td><td>EUR</td><td>Verbatim</td></tr>
      <tr><td>UK NBP gas</td><td><code>NBP</code></td><td>ICE_ENDEX</td><td>GBp/therm</td><td>GBp (pence)</td><td>Verbatim</td></tr>
      <tr><td>German THE gas</td><td><code>THE</code></td><td>ICE_ENDEX</td><td>EUR/MWh</td><td>EUR</td><td>Verbatim</td></tr>
      <tr><td>French PEG gas</td><td><code>PEG</code></td><td>ICE_ENDEX</td><td>EUR/MWh</td><td>EUR</td><td>Verbatim</td></tr>
      <tr><td>Belgian ZTP gas</td><td><code>ZTP</code></td><td>ICE_ENDEX</td><td>EUR/MWh</td><td>EUR</td><td>Verbatim</td></tr>
      <tr><td>Italian PSV gas</td><td><code>PSV</code></td><td>ICE_ENDEX</td><td>EUR/MWh</td><td>EUR</td><td>Verbatim</td></tr>
      <tr><td>EEX Phelix DE power</td><td><code>EEX_PHELIX_DE</code></td><td>EEX</td><td>EUR/MWh</td><td>EUR</td><td>Pending-verbatim</td></tr>
      <tr><td>EEX Phelix AT power</td><td><code>EEX_PHELIX_AT</code></td><td>EEX</td><td>EUR/MWh</td><td>EUR</td><td>Pending-verbatim</td></tr>
      <tr><td>EPEX DE power</td><td><code>EPEX_DE</code></td><td>EPEX_SPOT</td><td>EUR/MWh</td><td>EUR</td><td>Pending-verbatim</td></tr>
      <tr><td>EPEX FR power</td><td><code>EPEX_FR</code></td><td>EPEX_SPOT</td><td>EUR/MWh</td><td>EUR</td><td>Pending-verbatim</td></tr>
      <tr><td>EPEX NL power</td><td><code>EPEX_NL</code></td><td>EPEX_SPOT</td><td>EUR/MWh</td><td>EUR</td><td>Pending-verbatim</td></tr>
      <tr><td>EPEX BE power</td><td><code>EPEX_BE</code></td><td>EPEX_SPOT</td><td>EUR/MWh</td><td>EUR</td><td>Pending-verbatim</td></tr>
      <tr><td>EPEX GB power</td><td><code>EPEX_GB</code></td><td>EPEX_SPOT</td><td>GBP/MWh</td><td>GBP</td><td>Pending-verbatim</td></tr>
      <tr><td>EUA carbon</td><td><code>EUA</code></td><td>EEX</td><td>EUR/tCO2</td><td>EUR</td><td>Pending-verbatim</td></tr>
    </tbody></table><p>8 of 14 entries are <strong>pending-verbatim</strong>: the price_unit is asserted from the exchange landing page, but the exact wording is not yet captured verbatim (EPEX fetches returned HTTP 403 on 2026-07-18). The 6 ICE gas hubs are fully verbatim-cited. <code>PriceUnit</code> accepts denominators <code>{MWh, therm, MMBtu, tCO2, bbl, t}</code>; <code>tCO2</code> (emissions), <code>bbl</code> (barrel) and <code>t</code> (metric tonne) are <strong>energy-inconvertible</strong> &mdash; <code>convert_price</code> refuses to convert them to/from an energy denominator, since no calorific/heat-content value is assumed. No built-in registry entry currently uses <code>bbl</code> or <code>t</code>. <code>MBtu</code> is rejected (raises <code>ValidationError</code>, "did you mean MMBtu?").</p>
    <h2 id="conversion-constants">Energy-unit conversion constants</h2><table><thead><tr><th>Identity</th><th>Value</th><th>Source</th></tr></thead><tbody>
      <tr><td>1 therm</td><td>29.3071 kWh (<code>KWH_PER_THERM</code>)</td><td>ICE UK NBP contract spec</td></tr>
      <tr><td>1 therm</td><td>0.0293071 MWh (<code>MWH_PER_THERM</code>)</td><td>derived = KWH_PER_THERM / 1000</td></tr>
      <tr><td>1 MMBtu</td><td>10 therms (<code>THERMS_PER_MMBTU</code>)</td><td>definitional</td></tr>
      <tr><td>1 MMBtu</td><td>0.293071 MWh (<code>MWH_PER_MMBTU</code>)</td><td>derived = 10 &times; MWH_PER_THERM</td></tr>
      <tr><td>1 GBP</td><td>100 GBp (<code>PENCE_PER_POUND</code>)</td><td>UK decimal-currency subdivision</td></tr>
      <tr><td>bbl &rarr; MWh</td><td>none</td><td><strong>not specified</strong> &mdash; energy-inconvertible</td></tr>
      <tr><td>t (tonne) &rarr; MWh</td><td>none</td><td><strong>not specified</strong> &mdash; energy-inconvertible</td></tr>
      <tr><td>tCO2 &rarr; MWh</td><td>none</td><td>emissions, not energy</td></tr>
    </tbody></table>
    <h2 id="position-sign">Position signs</h2><p>A positive instrument notional represents a long position. Futures and forwards use <code>DF × (forward − contract price) × notional</code>. A swap is payer-of-fixed and receiver-of-floating. Scenario results report P&amp;L; VaR results report positive loss magnitudes.</p>
    <h2 id="time">Dates, periods and intervals</h2><p><code>DeliveryPeriod</code> represents one calendar month. Interval settlement requires timezone-aware UTC datetimes, ordered intervals, no overlap, no gaps where continuity is required, and consistent resolution.</p>
    <h2 id="cross-cutting">Cross-cutting conventions</h2><table><thead><tr><th>Convention</th><th>Rule</th></tr></thead><tbody>
      <tr><td>FX responsibility</td><td>Caller-supplied. <code>convert_price</code> converts only within one major currency (GBp&harr;GBP via /100); cross-major-currency conversion raises <code>ValidationError</code>. No FX rate, date or table lives in the library.</td></tr>
      <tr><td>Power vs energy</td><td>Prices are per energy unit (&hellip;/MWh). Contract size is <code>notional</code>, a plain positive float. The library carries no separate MW-vs-MWh tag beyond the <code>PriceUnit</code> denominator; the caller encodes the MW-capacity vs MWh-energy distinction.</td></tr>
      <tr><td>Sign / long-short</td><td>Direction is expressed only through <code>OptionSide{LONG,SHORT}</code>; <code>notional</code> is always strictly positive.</td></tr>
      <tr><td>Delta / Greek units</td><td>Greeks are scaled by side/notional in <code>portfolio/valuation.py</code>; same currency/energy basis as the position's price unit. Exact per-hub delta unit label: <strong>not specified</strong> (no unit string attached to Greeks).</td></tr>
      <tr><td>Delivery time zone</td><td>Delivery intervals are UTC, half-open <code>[start, end)</code>. Local calendar delivery days map to UTC per hub IANA time zone for the 7 ENTSO-E power hubs only.</td></tr>
      <tr><td>Gas-day boundary / gas-hub time zone</td><td><strong>Not specified in code.</strong> No IANA time zone or gas-day boundary is encoded for the 6 gas hubs or EUA.</td></tr>
      <tr><td>Day-count conventions</td><td>Exactly two: <code>actual_365</code> (default everywhere) and <code>actual_360</code> (money-market). Both signed; 0.0 on coincident dates; no 30/360.</td></tr>
      <tr><td>Discounting</td><td>Caller-supplied <code>DiscountCurve</code>; linear interpolation in the discount factor vs days-from-reference between bracketing tenors; outside the covered range raises <code>MissingTenorError</code> (no extrapolation).</td></tr>
      <tr><td>Contract-volume convention</td><td><code>notional</code> is a positive scalar; per-interval volume profiles (e.g. PPA) are caller-supplied Polars frames. Per-hub default volume: <strong>not specified</strong>.</td></tr>
    </tbody></table>
    <h2 id="randomness">Randomness</h2><p>Every stochastic public entry point accepts a seed. Documentation examples always pass one explicitly and record the path count alongside the result.</p>
    <h2 id="precision">Precision and tolerances</h2><p>Examples format currency for readability, but assertions should use numerical tolerances appropriate to the method. Monte Carlo results must be interpreted together with their standard error.</p>
  `},
  errors: {title:"Errors and validation", description:"QuantVolt fails before computation with an actionable public exception hierarchy.", body:`
    <h2 id="hierarchy">Exception hierarchy</h2><div class="exception-tree"><code>EnergyQuantError</code><div><code>ValidationError</code><code>InsufficientDataError</code><code>ArbitrageError</code><code>NoPricingDataError</code><code>ExpiredContractError</code><code>MissingTenorError</code><code>ScenarioNotFoundError</code><code>NumericalError</code><code>NativeExtensionError</code><code>DataSourceError</code><div><code>AuthenticationError</code><code>RateLimitError</code><code>DataUnavailableError</code></div></div></div>
    <p><code>ArbitrageError</code> is raised only when a curve carries non-finite prices, which make the calendar spreads undefined; a merely backwardated or non-monotonic curve is not an error &mdash; <code>check_arbitrage</code> returns that as <code>ArbitrageWarning</code> data, because carry inconsistency is not by itself tradable arbitrage.</p>
    <h2 id="validation">Catch the package base error</h2>${codeBlock(`import quantvolt as qv\n\ntry:\n    qv.DeliveryPeriod(2026, 13)\nexcept qv.EnergyQuantError as exc:\n    print(type(exc).__name__)\n    print(exc)`, `ValidationError\nmonth must be in [1, 12], got 13`)}
    <h2 id="missing-data">Missing coverage</h2>${codeBlock(`try:\n    curve.price_at(qv.DeliveryPeriod(2035, 1))\nexcept qv.MissingTenorError as exc:\n    print(exc)`, `forward curve has no price for DeliveryPeriod(year=2035, month=1)`)}
    <h2 id="recovery">Recovery policy</h2><p>Catch a specific exception when the caller can recover—for example by requesting another tenor after <code>MissingTenorError</code>. Catch <code>EnergyQuantError</code> only at an application boundary that reports or records all QuantVolt failures. Do not silently substitute values after validation errors.</p>
  `},
  testing: {title:"Testing QuantVolt workflows", description:"Verify non-mutation, deterministic replay and serialization in caller test suites.", body:`
    <h2 id="unchanged">Assert caller inputs are unchanged</h2>${codeBlock(`from quantvolt.testing import assert_input_unchanged\n\nresult = assert_input_unchanged(\n    qv.price_futures,\n    future, ttf_curve, valuation_date, discount_curve,\n)\nassert result.npv == expected_npv`, `✓ inputs equal their deep copies after pricing`)}
    <h2 id="deterministic">Test deterministic Monte Carlo</h2>${codeBlock(`first = asian_monte_carlo(\n    forward=36.85, strike=38.0, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n    averaging_points=12, option_type="call",\n    geometric=False, seed=7, path_count=50_000,\n)\nsecond = asian_monte_carlo(\n    forward=36.85, strike=38.0, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n    averaging_points=12, option_type="call",\n    geometric=False, seed=7, path_count=50_000,\n)\nassert first == second`, `✓ identical premium and standard error`)}
    <h2 id="round-trip">Test serialization round trips</h2>${codeBlock(`payload = curve.to_dict()\nrestored = qv.ForwardCurve.from_dict(payload)\nassert restored == curve`, `✓ exact model → dict → model round trip`)}
  `},
  design: {title:"Design guarantees", description:"Behavior QuantVolt commits to across the complete API.", body:`<h2 id="immutability">No mutation</h2><p>Public computations do not mutate caller data. Use <code>quantvolt.testing.assert_input_unchanged</code> to enforce the contract in your own tests.</p><h2 id="determinism">Deterministic randomness</h2><p>Monte Carlo entry points accept explicit seeds. The same inputs and seed reproduce the same paths and results.</p><h2 id="validation">Eager validation</h2><p>Bad inputs fail before computation, with an exception from the public <code>EnergyQuantError</code> hierarchy.</p><h2 id="typing">Typing and serialization</h2><p>The package ships <code>py.typed</code>. Domain results round-trip through plain dictionaries suitable for JSON.</p>`},
  markets: {title:"Supported markets", description:"Built-in European energy definitions, capability matrix and caller extensibility.", body:`<h2 id="capability-matrix">Supported-markets capability matrix</h2><p><code>Curves</code>/<code>Derivatives</code>/<code>Settlement</code> are largely library-wide, commodity-agnostic capabilities &mdash; pricers take forwards and vols, not a market ID &mdash; so a "Yes" is not an exchange-connectivity claim. A built-in ID is a commodity/price-unit identifier, not a live-feed integration.</p><table><thead><tr><th>Market / hub</th><th>Built-in ID</th><th>Native unit</th><th>Curves</th><th>Derivatives</th><th>Settlement</th><th>Free data adapter</th><th>External validation</th></tr></thead><tbody>
      <tr><td>EEX Phelix DE</td><td><code>EEX_PHELIX_DE</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>reBAP (DE)&sup2;</td><td>ENTSO-E, SMARD&sup3;</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>EEX Phelix AT</td><td><code>EEX_PHELIX_AT</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>ENTSO-E</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>EPEX DE</td><td><code>EPEX_DE</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>reBAP (DE)&sup2;</td><td>ENTSO-E, SMARD&sup3;</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>EPEX FR</td><td><code>EPEX_FR</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>ENTSO-E</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>EPEX NL</td><td><code>EPEX_NL</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>ENTSO-E</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>EPEX BE</td><td><code>EPEX_BE</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>ENTSO-E</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>EPEX GB</td><td><code>EPEX_GB</code></td><td>GBP/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>ENTSO-E</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>TTF gas</td><td><code>TTF</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>none (fundamentals only via ENTSOG&sup5;)</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>NBP gas</td><td><code>NBP</code></td><td>GBp/therm</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>none&sup5;</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>THE gas</td><td><code>THE</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>none&sup5;</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>PEG gas</td><td><code>PEG</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>none&sup5;</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>ZTP gas</td><td><code>ZTP</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>none&sup5;</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>PSV gas</td><td><code>PSV</code></td><td>EUR/MWh</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>none&sup5;</td><td>Pricer-level&sup4;</td></tr>
      <tr><td>EUA carbon</td><td><code>EUA</code></td><td>EUR/tCO2</td><td>Caller/commercial-stub</td><td>Library-wide&sup1;</td><td>Caller-supplied</td><td>none (commercial stub only)</td><td>Pricer-level&sup4;</td></tr>
    </tbody></table><p><small>&sup1; Library-wide (commodity-agnostic): Black-76, Bachelier, spread (Kirk/Margrabe), spark/dark/clean/crack spreads, Asian, barrier, lookback, futures, swap, tolling, transmission-right and PPA pricers take caller forwards/vols/curves &mdash; they are not wired to any hub's live exchange feed. &sup2; reBAP settlement is DE-LU only; the settle functions themselves are commodity-agnostic given caller data. &sup3; SMARD covers DE-LU day-ahead only. &sup4; External validation (QuantLib 1.43 fixtures) is pricer-level, not market-level &mdash; it validates the kernel regardless of which hub supplies the forward. &sup5; No free adapter exposes a gas/EUA forward or spot price; ENTSOG gives flows (fundamentals), not hub price. Gas/EUA curves come only from commercial stubs or caller-supplied data.</small></p>
    <h2 id="custom">Custom commodities</h2>${codeBlock(`registry = qv.merge_commodities({"MY_HUB": custom_config})\ncommodity = registry["MY_HUB"]`, `Built-ins preserved · caller definition added`)}`}
};

function escapeHTML(value) { return value.replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;"); }
function codeBlock(code, output, language="python", visual="") { return `<div class="example-block"><div class="code-head"><span>${language}</span><button data-copy="${escapeHTML(code).replaceAll('"', '&quot;')}">Copy</button></div><pre><code>${highlight(code)}</code></pre><div class="output-head"><span>Result</span><span>reproducible output</span></div>${visual}<pre class="output"><code>${escapeHTML(output)}</code></pre></div>`; }
function highlight(code) { return escapeHTML(code).replace(/(&quot;.*?&quot;)/g, '<span class="str">$1</span>').replace(/\b(import|from|as|print|assert|for|in)\b/g, '<span class="kw">$1</span>').replace(/\b(\d+(?:\.\d+)?)\b/g, '<span class="num">$1</span>'); }
function miniCurve(){return `<svg class="result-chart" viewBox="0 0 600 120" preserveAspectRatio="none"><path class="area" d="M0 100L120 75L240 35L360 48L480 62L600 72V120H0Z"/><path class="line" d="M0 100L120 75L240 35L360 48L480 62L600 72"/></svg>`}
function distributionChart(){return `<svg class="result-chart" viewBox="0 0 600 120" preserveAspectRatio="none"><path class="area" d="M0 115C150 114 170 90 230 65C270 25 330 25 370 65C430 90 450 114 600 115V120H0Z"/><path class="line" d="M0 115C150 114 170 90 230 65C270 25 330 25 370 65C430 90 450 114 600 115"/><path class="risk-line" d="M150 10V116"/></svg>`}
function dispatchChart(){return `<div class="dispatch-chart">${Array.from({length:24},(_,i)=>`<i class="${[0,1,6,7,8,9,10,16,17,18,19,20,21].includes(i)?'active':''}" style="height:${15+(i*29)%80}%"></i>`).join('')}</div>`}
